SELECT t.trial_id, c.country_name, t.publication_status
FROM trials t
JOIN countries c ON t.country = c.country_name;

SELECT intervention
FROM trials
WHERE country = 'Egypt' AND intervention = 'Lanreotide';

SELECT country_name, population
FROM countries
WHERE population IN (
    (SELECT MAX(population) FROM countries),
    (SELECT MIN(population) FROM countries)
);

SELECT country, publication_status, intervention, control, age_intervention, age_control 
FROM trials 
WHERE trial_id IN (SELECT trial_id FROM access_logs);

SELECT user_name 
FROM users 
WHERE user_id = (SELECT last_updated_by FROM trials WHERE trial_id = 1);

SELECT DISTINCT intervention
FROM trials
WHERE country = 'United States' AND publication_status = 'Published';

SELECT trials.authors, interventions.intervention_name 
FROM trials 
INNER JOIN interventions ON trials.intervention = interventions.intervention_id;

SELECT intervention_name
FROM interventions
WHERE intervention_id = 1;
